    fn deterministic_partition_offset_runtime(
        &self,
        group_key: &str,
        branch_count: usize,
    ) -> usize {
        if branch_count <= 1 {
            return 0;
        }
        let mut hash: u64 = 0xcbf2_9ce4_8422_2325;
        for byte in group_key.as_bytes() {
            hash ^= *byte as u64;
            hash = hash.wrapping_mul(0x0000_0100_0000_01B3);
        }
        (hash as usize) % branch_count
    }
